import * as React from 'react';
import Box from '@mui/material/Box';
import AppBar from '@mui/material/AppBar';
import Button from '@mui/material/Button';
import Grid from '@mui/material/Grid';
import Link from '@mui/material/Link';
import { styled } from '@mui/material/styles';
import { useNavigate } from 'react-router-dom';

// import Daylight from './collections/Daylight';
// import Dust from './collections/Dust';
// import Escape from './collections/Escape';
// import Illusion from './collections/Illusion';
// import Mountains from './collections/Mountains';
// import NiceDream from './collections/NiceDream';
// import RoseGold from './collections/RoseGold';
// import Stay from './collections/Stay';
// import Times from './collections/Times';
// import Voyages from './collections/Voyages';

const LinkButton = styled(Button)(() => ({
  // backgroundColor: 'yellow',
  width: '100%',
  height: '100%',
  borderRadius: '0px',
}));

function SubHeader () {
  const navigate = useNavigate();

  return (
    <>
      <AppBar
        position='static'
        color='inherit'
        sx={{
          // display: 'flex',
          // justifyContent: 'center',
          // alignItems: 'center',
          boxShadow: '0px 0px 0px #e3e3e3',
          // backgroundColor: 'red',
          // marginTop: '86px',
          // {
          //   xs: '86px', // needs fixing
          //   sm: '86px', // needs fixing
          //   md: '86px',
          //   lg: '86px',
          //   xl: '86px',
          // }
        }}
      >
        <Box
          sx={{
            // display: {
            //   xs: 'block',  // 2 columns menu
            //   sm: 'block',   // 4 columns menu
            //   md: 'block'
            // },
            display: 'block',
            margin: '86px 10% 30px',
            // marginLeft: '10%',
            // marginRight: '10%',
            // marginTop: '86px',
            // marginBottom: '30px'
            // backgroundColor: 'yellow',
          }}
        >
          <Grid container columns={{ xs: 2, sm: 5, lg: 10 }} gap={0} justifyContent={'center'}>
            <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }}>
              <LinkButton onClick={() => navigate('/collections/daylight')} color='inherit'>Daylight</LinkButton>
            </Grid>
            <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }}>
              <LinkButton onClick={() => navigate('/collections/dust')} color='inherit'>Dust</LinkButton>
            </Grid>
            <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }}>
              <LinkButton onClick={() => navigate('/collections/escape')} color='inherit'>Escape</LinkButton>
            </Grid>
            <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }}>
              <LinkButton onClick={() => navigate('/collections/illusion')} color='inherit'>Illusion</LinkButton>
            </Grid>
            <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }}>
              <LinkButton onClick={() => navigate('/collections/mountains')} color='inherit'>Mountains</LinkButton>
            </Grid>
            <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }}>
              <LinkButton onClick={() => navigate('/collections/nicedream')} color='inherit'>Nice Dream</LinkButton>
            </Grid>
            <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }}>
              <LinkButton onClick={() => navigate('/collections/rosegold')} color='inherit'>Rose Gold</LinkButton>
            </Grid>
            <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }}>
              <LinkButton onClick={() => navigate('/collections/stay')} color='inherit'>Stay</LinkButton>
            </Grid>
            <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }}>
              <LinkButton onClick={() => navigate('/collections/times')} color='inherit'>Times</LinkButton>
            </Grid>
            <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }}>
              <LinkButton onClick={() => navigate('/collections/voyages')} color='inherit'>Voyages</LinkButton>
            </Grid>
          </Grid>
        </Box>
      </AppBar>
    </>
  )
}

export default SubHeader;
